                    value.Name = tlv.GetUTF8String(0);
                    break;
                case 1:
                    value.Role = tlv.GetUTF8String(1);
                    break;
                default:
                    tlv.SkipElement();
                    break;
            }
        }

        tlv.CloseContainer();
        return value;
    }

    private static PageTokenStruct ReadPageTokenStruct(MatterTLV tlv)
        => ReadPageTokenStruct(tlv, null);

    private static PageTokenStruct ReadPageTokenStruct(MatterTLV tlv, int? tag)
    {
        var value = new PageTokenStruct();
        tlv.OpenStructure(tag);
        while (!tlv.IsEndContainerNext())
        {
            switch (tlv.PeekTag())
            {
                case 0:
                    if (tlv.IsNextNull()) { tlv.GetNull(0); } else { value.Limit = (ushort)tlv.GetUnsignedIntAny(0); }
                    break;
                case 1:
                    if (tlv.IsNextNull()) { tlv.GetNull(1); } else { value.After = tlv.GetUTF8String(1); }
                    break;
                case 2:
                    if (tlv.IsNextNull()) { tlv.GetNull(2); } else { value.Before = tlv.GetUTF8String(2); }
                    break;
                default:
                    tlv.SkipElement();
                    break;
            }
        }

        tlv.CloseContainer();
        return value;
    }

    private static ChannelPagingStruct ReadChannelPagingStruct(MatterTLV tlv)
        => ReadChannelPagingStruct(tlv, null);

    private static ChannelPagingStruct ReadChannelPagingStruct(MatterTLV tlv, int? tag)
    {
        var value = new ChannelPagingStruct();
        tlv.OpenStructure(tag);
        while (!tlv.IsEndContainerNext())
        {
            switch (tlv.PeekTag())
            {
                case 0:
                    if (tlv.IsNextNull()) { tlv.GetNull(0); } else { value.PreviousToken = ReadPageTokenStruct(tlv); }
                    break;
                case 1:
                    if (tlv.IsNextNull()) { tlv.GetNull(1); } else { value.NextToken = ReadPageTokenStruct(tlv); }
                    break;
                default:
                    tlv.SkipElement();
                    break;
            }
        }

        tlv.CloseContainer();
        return value;
    }

    private static AdditionalInfoStruct ReadAdditionalInfoStruct(MatterTLV tlv)
        => ReadAdditionalInfoStruct(tlv, null);

    private static AdditionalInfoStruct ReadAdditionalInfoStruct(MatterTLV tlv, int? tag)
    {
        var value = new AdditionalInfoStruct();
        tlv.OpenStructure(tag);
        while (!tlv.IsEndContainerNext())
        {
            switch (tlv.PeekTag())
            {
                case 0:
                    value.Name = tlv.GetUTF8String(0);
                    break;
                case 1:
                    value.Value = tlv.GetUTF8String(1);
                    break;
                default:
                    tlv.SkipElement();
                    break;
            }
        }

        tlv.CloseContainer();
        return value;
    }

    /// <summary>Attribute identifiers.</summary>
    public static class Attributes
    {
        /// <summary>ChannelList (0x0000).</summary>
        public const uint ChannelList = 0x0000;
        /// <summary>Lineup (0x0001).</summary>
        public const uint Lineup = 0x0001;
        /// <summary>CurrentChannel (0x0002).</summary>
        public const uint CurrentChannel = 0x0002;
    }

    /// <summary>Command identifiers.</summary>
    public static class Commands
    {
        /// <summary>ChangeChannel (0x0000).</summary>
        public const uint ChangeChannel = 0x0000;
        /// <summary>ChangeChannelByNumber (0x0002).</summary>
        public const uint ChangeChannelByNumber = 0x0002;
        /// <summary>SkipChannel (0x0003).</summary>
        public const uint SkipChannel = 0x0003;
        /// <summary>GetProgramGuide (0x0004).</summary>
        public const uint GetProgramGuide = 0x0004;
        /// <summary>RecordProgram (0x0006).</summary>
        public const uint RecordProgram = 0x0006;
        /// <summary>CancelRecordProgram (0x0007).</summary>
        public const uint CancelRecordProgram = 0x0007;
    }

    // Async command methods

    /// <summary>Send ChangeChannel command (0x0000).</summary>
    public Task<InvokeResponse> ChangeChannelAsync(
        string match,
        CancellationToken ct = default)
        => InvokeCommandAsync(0x0000, tlv => { tlv.AddUTF8String(0, match); }, ct);

    /// <summary>Send ChangeChannelByNumber command (0x0002).</summary>
    public Task<InvokeResponse> ChangeChannelByNumberAsync(
        ushort majorNumber,
        ushort minorNumber,
        CancellationToken ct = default)
        => InvokeCommandAsync(0x0002, tlv =>
        {
            tlv.AddUInt16(0, majorNumber);
            tlv.AddUInt16(1, minorNumber);
        }, ct);

    /// <summary>Send SkipChannel command (0x0003).</summary>
    public Task<InvokeResponse> SkipChannelAsync(
        short count,
        CancellationToken ct = default)
        => InvokeCommandAsync(0x0003, tlv => { tlv.AddInt16(0, count); }, ct);

    /// <summary>Send GetProgramGuide command (0x0004).</summary>
    public Task<InvokeResponse> GetProgramGuideAsync(
        uint? startTime = default,
        uint? endTime = default,
        ChannelInfoStruct[]? channelList = default,
        PageTokenStruct? pageToken = default,
        RecordingFlagBitmap? recordingFlag = default,
        AdditionalInfoStruct[]? externalIDList = default,
        byte[]? data = default,
        CancellationToken ct = default)
        => InvokeCommandAsync(0x0004, tlv =>
        {
            if (startTime != null) tlv.AddUInt32(0, startTime.Value);
            if (endTime != null) tlv.AddUInt32(1, endTime.Value);
            if (channelList != null) { tlv.AddArray(2); foreach (var item in channelList) { WriteChannelInfoStruct(tlv, item); } tlv.EndContainer(); }
            if (pageToken != null) WritePageTokenStruct(tlv, 3, pageToken);
            if (recordingFlag != null) tlv.AddUInt32(4, (uint)recordingFlag);
            if (externalIDList != null) { tlv.AddArray(5); foreach (var item in externalIDList) { WriteAdditionalInfoStruct(tlv, item); } tlv.EndContainer(); }
            if (data != null) tlv.AddOctetString(6, data);
        }, ct);

    /// <summary>Send RecordProgram command (0x0006).</summary>
    public Task<InvokeResponse> RecordProgramAsync(
        string programIdentifier,
        bool shouldRecordSeries,
        AdditionalInfoStruct[] externalIDList,
        byte[] data,
        CancellationToken ct = default)
        => InvokeCommandAsync(0x0006, tlv =>
        {
            tlv.AddUTF8String(0, programIdentifier);
            tlv.AddBool(1, shouldRecordSeries);
            if (externalIDList != null) { tlv.AddArray(2); foreach (var item in externalIDList) { WriteAdditionalInfoStruct(tlv, item); } tlv.EndContainer(); }
            tlv.AddOctetString(3, data);
        }, ct);

    /// <summary>Send CancelRecordProgram command (0x0007).</summary>
    public Task<InvokeResponse> CancelRecordProgramAsync(
        string programIdentifier,
        bool shouldRecordSeries,
        AdditionalInfoStruct[] externalIDList,
        byte[] data,
        CancellationToken ct = default)
        => InvokeCommandAsync(0x0007, tlv =>
        {
            tlv.AddUTF8String(0, programIdentifier);
            tlv.AddBool(1, shouldRecordSeries);
            if (externalIDList != null) { tlv.AddArray(2); foreach (var item in externalIDList) { WriteAdditionalInfoStruct(tlv, item); } tlv.EndContainer(); }
            tlv.AddOctetString(3, data);
        }, ct);

    // Attribute readers

    /// <summary>Read ChannelList attribute (0x0000).</summary>
    public Task<ChannelInfoStruct[]?> ReadChannelListAsync(CancellationToken ct = default)
        => ReadArrayAttributeAsync(0x0000, ReadChannelInfoStruct, ct);

    /// <summary>Read Lineup attribute (0x0001).</summary>
    public Task<LineupInfoStruct?> ReadLineupAsync(CancellationToken ct = default)
        => ReadStructAttributeAsync(0x0001, raw => ReadLineupInfoStruct(raw, 2), ct);

    /// <summary>Read CurrentChannel attribute (0x0002).</summary>
    public Task<ChannelInfoStruct?> ReadCurrentChannelAsync(CancellationToken ct = default)
        => ReadStructAttributeAsync(0x0002, raw => ReadChannelInfoStruct(raw, 2), ct);
}
